// document_text is now extracted client-side by the frontend (PDF.js for PDFs,
// mammoth for DOCX/DOC, native File.text() for TXT) and sent as plain UTF-8.
// No base64 decoding needed here — just pass it through.
const body = $input.first().json.body ?? $input.first().json;
const document_text = body.document_text ?? '(no document text provided)';
return [{ json: { ...body, document_text } }];

// FIX 3 — Parse the Orchestrator Agent's text output into a clean JSON envelope
// that matches the shape the frontend expects:
// { contract_type, key_terms[], terms_found[], terms_missing[], risk_score, risk_flags[], status }

const raw = $input.first().json.output ?? '';

let parsed = null;
try {
  // Strip markdown code fences if the LLM wrapped its output
  const cleaned = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
  parsed = JSON.parse(cleaned);
} catch {
  // JSON parse failed — return a detectable error envelope so the frontend
  // can fall back to MOCK_ANALYSIS rather than silently showing nothing.
  return [{
    json: {
      status: 'parse_error',
      raw_output: raw.slice(0, 500),
      contract_type: null,
      key_terms: [],
      terms_found: [],
      terms_missing: [],
      risk_score: null,
      risk_flags: [],
      analyzed_at: new Date().toISOString()
    }
  }];
}

const key_terms = Array.isArray(parsed.key_terms) ? parsed.key_terms : [];

// Separate found vs missing based on value content
const terms_found   = key_terms
  .filter(t => t.value && t.value !== 'Not specified' && t.value !== 'not found')
  .map(t => (t.label ?? '').toLowerCase().replace(/[\s-]+/g, '_'));

const terms_missing = key_terms
  .filter(t => !t.value || t.value === 'Not specified' || t.value === 'not found')
  .map(t => (t.label ?? '').toLowerCase().replace(/[\s-]+/g, '_'));

return [{
  json: {
    status: 'ok',
    contract_type:  parsed.contract_type  ?? null,
    parties:        parsed.parties        ?? [],
    effective_date: parsed.effective_date ?? null,
    key_terms,
    terms_found,
    terms_missing,
    // risk_score and risk_flags are not yet computed by n8n;
    // frontend fills these from MOCK_ANALYSIS when null.
    risk_score:  null,
    risk_flags:  [],
    analyzed_at: new Date().toISOString()
  }
}];
